export const RecommendedArtists = ({ userInfo, loading }) => {
	return (
		<div className="list-container">
			{loading ? (
				<h3>Loading...</h3>
			) : (
				userInfo?.map((item, i) => (
					<div className="single-item" key={i}>
						<a href={item.spotify_url}>
							<img src={item.image} alt="track_pi" />
							<p>{item.track_title}</p>
						</a>
					</div>
				))
			)}
		</div>
	);
};
